 72→    return (
 73→        <div className={styles.rocketHud}>
 74→            {/* Exit button */}
 75→            <button className={styles.rocketExitBtn} onClick={onExit} disabled={isDocking}>
 76→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
 77→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 78→                </svg>
 79→                Exit Rocket
 80→            </button>
